        <div className="rounded-md border border-border bg-card p-4">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <div>
              <h3 className="text-sm font-semibold text-white">
                Image retry presets
              </h3>
              <p className="mt-1 text-xs text-gray-500">
                Used by Retry image export and Re-export images only actions.
              </p>
            </div>
            <Button
              type="button"
              variant="outline"
              size="sm"
              onClick={handleResetImageRetryPresets}
              disabled={!imageRetryPresetsLoaded}
              className="border"
            >
              Reset defaults
            </Button>
          </div>
          {!imageRetryPresetsLoaded ? (
            <p className="mt-3 text-xs text-gray-500">Loading presets...</p>
          ) : (
            <div className="mt-3 space-y-3">
              {imageRetryPresets.map((preset: ImageRetryPreset) => (
                <div
                  key={preset.id}
                  className="rounded-md border border-border bg-card/60 p-3"
                >
                  <div className="text-xs font-semibold text-gray-200">
                    {preset.label}
                  </div>
                  <div className="mt-1 text-[11px] text-gray-500">
                    {preset.description}
                  </div>
                  <div className="mt-2 grid gap-3 md:grid-cols-2">
                    <div>
                      <Label className="text-[10px] text-gray-500">
                        Max dimension (px)
                      </Label>
                      <Input
                        type="number"
                        min={1}
                        value={preset.transform.maxDimension ?? ""}
                        onChange={(
                          event: React.ChangeEvent<HTMLInputElement>,
                        ): void => {
                          const raw = event.target.value;
                          updateImageRetryPreset(preset.id, {
                            ...(raw ? { maxDimension: Number(raw) } : {}),
                          });
                        }}
                        className="mt-1 h-8"
                      />
                    </div>
                    <div>
                      <Label className="text-[10px] text-gray-500">
                        JPEG quality
                      </Label>
                      <Input
                        type="number"
                        min={10}
                        max={100}
                        value={preset.transform.jpegQuality ?? ""}
                        onChange={(
                          event: React.ChangeEvent<HTMLInputElement>,
                        ): void => {
                          const raw = event.target.value;
                          updateImageRetryPreset(preset.id, {
                            ...(raw ? { jpegQuality: Number(raw) } : {}),
                          });
                        }}
                        className="mt-1 h-8"
                      />
                    </div>
                  </div>
                  <div className="mt-2 flex items-center gap-2 text-[11px] text-gray-400">
                    <Checkbox
                      checked={preset.transform.forceJpeg ?? true}
                      onCheckedChange={(
                        checked: boolean | "indeterminate",
                      ): void =>
                        updateImageRetryPreset(preset.id, {
                          forceJpeg: Boolean(checked),
                        })
                      }
                      className="h-3 w-3 rounded border bg-gray-900 text-emerald-500"
                    />
                    <span>Force JPEG conversion</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="rounded-md border border-blue-900/50 bg-blue-900/20 p-4">
          <h3 className="text-sm font-semibold text-blue-200">
            Export Guidelines
          </h3>
          <ul className="mt-2 space-y-1 text-xs text-blue-300/70">
            <li>
              • Exports use templates to map internal product fields to Base.com
              API parameters
            </li>
            <li>
              • Without a template, default field mappings are used (SKU, Name,
              Price, Stock, etc.)
            </li>
            <li>
              • Import and export templates are managed separately in the
              Templates tab
            </li>
            <li>
              • Export to Base.com from Product List → Integrations → List
              Products → Select Base.com
            </li>
            <li>
              • Track export jobs in the{" "}
              <Link
                href="/admin/products/jobs?tab=export"
                className="text-blue-400 underline"
              >
                Export Jobs
              </Link>{" "}
              tab
            </li>
          </ul>
        </div>

        <div className="rounded-md border border-border bg-card p-4">
          <h3 className="text-sm font-semibold text-white mb-3">
            Quick Actions
          </h3>
          <div className="flex flex-wrap gap-3">
            <Button
              onClick={(): void => {
                void handleLoadInventories();
              }}
              disabled={loadingInventories}
              variant="outline"
              size="sm"
              className="border"
            >
              {loadingInventories ? "Loading..." : "Load Inventories"}
            </Button>
            <Button
              onClick={(): void => {
                void handleLoadWarehouses();
              }}
              disabled={loadingWarehouses}
              variant="outline"
              size="sm"
              className="border"
            >
              {loadingWarehouses ? "Loading..." : "Load Warehouses"}
            </Button>
            <Button
              onClick={(): void => {
                void handleDebugWarehouses();
              }}
              disabled={loadingDebugWarehouses}
              variant="outline"
              size="sm"
              className="border"
            >
              {loadingDebugWarehouses ? "Debugging..." : "Debug Warehouses"}
            </Button>
            <div className="flex items-center gap-2 text-xs text-gray-400">
              <Checkbox
                id="includeAllWarehouses"
                checked={includeAllWarehouses}
                onCheckedChange={(checked: boolean | "indeterminate"): void =>
                  setIncludeAllWarehouses(Boolean(checked))
                }
                className="h-3 w-3 rounded border bg-gray-900 text-emerald-500"
              />
              <Label htmlFor="includeAllWarehouses">
                Try loading global warehouses (if supported)
              </Label>
            </div>
            <Button
              onClick={(): void => {
                void handleSaveExportSettings();
              }}
              disabled={savingExportSettings}
              size="sm"
            >
              {savingExportSettings ? "Saving..." : "Save Export Settings"}
            </Button>
            <Link href="/admin/products/jobs?tab=export">
              <Button variant="outline" size="sm" className="border">
                View Listing Jobs
              </Button>
            </Link>
            <Link href="/admin/products">
              <Button variant="outline" size="sm" className="border">
                Go to Products
              </Button>
            </Link>
          </div>
        </div>
        {debugWarehouses ? (
          <div className="rounded-md border border-border bg-card/60 p-3 text-xs text-gray-300">
            <div className="flex flex-wrap items-center justify-between gap-2">
              <span className="font-semibold text-gray-200">
                Warehouse debug (raw IDs)
              </span>
              <Button
                type="button"
                onClick={(): void => setDebugWarehouses(null)}
                className="text-[11px] uppercase tracking-wide text-gray-500 hover:text-gray-200"
              >
                Clear
              </Button>
            </div>
            <div className="mt-2 space-y-2">
              <div>
                <div className="text-[11px] uppercase tracking-wide text-gray-500">
                  Selected inventory raw response
                </div>
                {debugWarehouses.inventoriesRaw ? (
                  <div className="mt-1 space-y-1 text-[11px] text-gray-400">
                    <div>Method: {debugWarehouses.inventoriesRaw.method}</div>
                    <div>
                      Status: {debugWarehouses.inventoriesRaw.statusCode}
                    </div>
                    <div>
                      Ok: {debugWarehouses.inventoriesRaw.ok ? "true" : "false"}
                    </div>
                    {debugWarehouses.inventoriesRaw.error ? (
                      <div>Error: {debugWarehouses.inventoriesRaw.error}</div>
                    ) : null}
                    {((): React.JSX.Element | null => {
                      const payload = debugWarehouses.inventoriesRaw
                        ?.payload as Record<string, unknown> | null | undefined;
                      const inventories = payload
                        ? payload["inventories"]
                        : null;
                      if (!Array.isArray(inventories)) return null;
                      const match = (
                        inventories as Array<Record<string, unknown>>
                      ).find((inv: Record<string, unknown>) => {
                        if (!inv || typeof inv !== "object") return false;
                        const inventoryId = inv["inventory_id"];
                        return (
                          exportInventoryId &&
                          (typeof inventoryId === "string" ||
                            typeof inventoryId === "number") &&
                          String(inventoryId) === exportInventoryId
                        );
                      });
                      if (!match) {
                        return (
                          <div className="rounded border border-border bg-card/60 p-2 text-[10px] text-gray-300">
                            Selected inventory not found in response.
                          </div>
                        );
                      }
                      return (
                        <div className="rounded border border-border bg-card/60 p-2 text-[10px] text-gray-300">
                          <div className="text-[11px] uppercase tracking-wide text-gray-500">
                            Selected inventory details
                          </div>
                          <pre className="mt-1 whitespace-pre-wrap">
                            {JSON.stringify(match, null, 2)}
                          </pre>
                        </div>
                      );
                    })()}
                  </div>
                ) : (
                  <div className="mt-1 text-gray-500">No raw response.</div>
                )}
              </div>
              <div>
                <div className="text-[11px] uppercase tracking-wide text-gray-500">
                  Inventory warehouses raw response
                </div>
                {debugWarehouses.inventoryRaw ? (
                  <div className="mt-1 space-y-1 text-[11px] text-gray-400">
                    <div>Inventory ID: {exportInventoryId || "—"}</div>
                    <div>Method: {debugWarehouses.inventoryRaw.method}</div>
                    <div>Status: {debugWarehouses.inventoryRaw.statusCode}</div>
                    <div>
                      Ok: {debugWarehouses.inventoryRaw.ok ? "true" : "false"}
                    </div>
                    {debugWarehouses.inventoryRaw.error ? (
                      <div>Error: {debugWarehouses.inventoryRaw.error}</div>
                    ) : null}
                    <pre className="mt-2 max-h-64 overflow-auto rounded border border-border bg-card p-2 text-[10px] text-gray-300">
                      {debugWarehouses.inventoryRaw.payload
                        ? JSON.stringify(
                            debugWarehouses.inventoryRaw.payload,
                            null,
                            2,
                          )
                        : "No payload returned."}
                    </pre>
                  </div>
                ) : (
                  <div className="mt-1 text-gray-500">No raw response.</div>
                )}
              </div>
            </div>
          </div>
        ) : null}
      </div>
    </div>
  );
}

"use client";

import { Button, Input, Label, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, DropdownMenu, DropdownMenuCheckboxItem, DropdownMenuContent, DropdownMenuTrigger } from "@/shared/ui";
import { useMemo, useState } from "react";
import { useFormContext } from "react-hook-form";
import { useProductFormContext } from "@/features/products/context/ProductFormContext";



import { X } from "lucide-react";


import { ProductFormData, CatalogRecord, ProductCategory, ProductTag, PriceGroupWithDetails } from "@/features/products/types";

export default function ProductFormOther(): React.JSX.Element {
  const {
    errors,
    catalogs,
    catalogsLoading,
    catalogsError,
    selectedCatalogIds,
    toggleCatalog,
    categories,
    categoriesLoading,
    selectedCategoryIds,
    toggleCategory,
    tags,
    tagsLoading,
    selectedTagIds,
    toggleTag,
    filteredPriceGroups,
    product,
  } = useProductFormContext();

  const { register, setValue, getValues, watch } = useFormContext<ProductFormData>();

  const basePrice = watch("price") || 0;
  const selectedDefaultPriceGroupId = watch("defaultPriceGroupId");
  const hasCatalogs = selectedCatalogIds.length > 0;
  const selectedCatalogLabels = catalogs
    .filter((catalog: CatalogRecord) => selectedCatalogIds.includes(catalog.id))
    .map((catalog: CatalogRecord) => catalog.name);
  const selectedCatalogSummary = selectedCatalogLabels.length
    ? selectedCatalogLabels.join(", ")
    : "Select catalogs";

  // Check if price group is auto-assigned from catalog (for new products only)
  const isNewProduct = !product;
  const selectedCatalog = catalogs.find((c: CatalogRecord) => selectedCatalogIds.includes(c.id));
  const isPriceGroupAutoAssigned = !!(isNewProduct && selectedCatalog?.defaultPriceGroupId);
  const [categoryQuery, setCategoryQuery] = useState("");
  const [tagQuery, setTagQuery] = useState("");
  const filteredCategories = useMemo(() => {
    const normalized = categoryQuery.trim().toLowerCase();
    if (!normalized) return categories;
    return categories.filter((category: ProductCategory) =>
      category.name.toLowerCase().includes(normalized)
    );
  }, [categories, categoryQuery]);
  const filteredTags = useMemo(() => {
    const normalized = tagQuery.trim().toLowerCase();
    if (!normalized) return tags;
    return tags.filter((tag: ProductTag) => tag.name.toLowerCase().includes(normalized));
  }, [tags, tagQuery]);

  // Calculate prices for all price groups
  const priceGroupPrices = filteredPriceGroups.map((group: PriceGroupWithDetails) => {
    if (!group.sourceGroupId || !group.priceMultiplier) {
      // This is a base price group (not dependent)
      return {
        ...group,
        calculatedPrice: group.id === selectedDefaultPriceGroupId ? basePrice : null,
        isCalculated: false,
        sourceGroupName: undefined as string | undefined,
      };
    }

    // This is a dependent price group
    // Find the source group's price
    const sourceGroup = filteredPriceGroups.find((g: PriceGroupWithDetails) => g.id === group.sourceGroupId);
    if (!sourceGroup) {
      return {
        ...group,
        calculatedPrice: null,
        isCalculated: true,
        sourceGroupName: undefined as string | undefined,
      };
    }

    // If the source group is the selected default, use the base price
    const sourcePrice = sourceGroup.id === selectedDefaultPriceGroupId ? basePrice : null;
    const calculatedPrice = sourcePrice ? sourcePrice * group.priceMultiplier : null;

    return {
      ...group,
      calculatedPrice,
      isCalculated: true,
      sourceGroupName: sourceGroup.name as string | undefined,
    };
  });

  return (
    <div className="space-y-4">
      {!hasCatalogs && (
        <div className="rounded-md border border-amber-500/40 bg-amber-500/10 px-4 py-3 text-sm text-amber-100">
          Select a catalog to set pricing and price groups.
        </div>
      )}
      {hasCatalogs && (
        <>
          <div className="mb-4">
            <Label htmlFor="price">Base Price</Label>
            <Input
              id="price"
              type="number"
              step="0.01"
              {...register("price", { valueAsNumber: true })}
              aria-invalid={errors.price ? "true" : "false"}
            />
            {errors.price && (
              <p className="text-red-500 text-sm mt-1" role="alert">
                {errors.price.message}
              </p>
            )}
          </div>
          <div className="mb-4">
            <Label htmlFor="defaultPriceGroupId">
              Default Price Group
              {isPriceGroupAutoAssigned && (
                <span className="ml-2 text-xs text-muted-foreground">(Auto-assigned from catalog)</span>
              )}
            </Label>
            <Select
              onValueChange={(value: string) => setValue("defaultPriceGroupId", value)}
              value={getValues("defaultPriceGroupId") || ""}
              disabled={isPriceGroupAutoAssigned}
            >
              <SelectTrigger className={isPriceGroupAutoAssigned ? "cursor-not-allowed opacity-60" : ""}>
                <SelectValue placeholder="Select default price group" />
              </SelectTrigger>
              <SelectContent>
                {filteredPriceGroups.map((group: PriceGroupWithDetails) => (
                  <SelectItem key={group.id} value={group.id}>
                    {group.name} {group.isDefault ? "(Default)" : ""}{" "}
                    ({group.currency?.code ?? group.currencyCode})
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
          {selectedDefaultPriceGroupId && filteredPriceGroups.length > 0 && (
            <div className="mb-4">
              <Label className="mb-2 block">Price Groups Overview</Label>
              <div className="rounded-md border">
                <table className="w-full text-sm">
                  <thead className="border-b bg-muted/50">
                    <tr>
                      <th className="px-3 py-2 text-left font-medium">Price Group</th>
                      <th className="px-3 py-2 text-left font-medium">Currency</th>
                      <th className="px-3 py-2 text-right font-medium">Price</th>
                    </tr>
                  </thead>
                  <tbody>
                    {priceGroupPrices.map((group: any) => (
                      <tr key={group.id} className="border-b last:border-0">
                        <td className="px-3 py-2">
                          <div className="flex items-center gap-2">
                            <span className={group.id === selectedDefaultPriceGroupId ? "font-semibold" : ""}>
                              {group.name}
                            </span>
                            {group.id === selectedDefaultPriceGroupId && (
                              <span className="text-xs text-muted-foreground">(Selected)</span>
                            )}
                            {group.isCalculated && group.sourceGroupName && (
                              <span className="text-xs text-muted-foreground">
                                (from {group.sourceGroupName} × {group.priceMultiplier})
                              </span>
                            )}
                          </div>
                        </td>
                        <td className="px-3 py-2">{group.currency?.code ?? group.currencyCode}</td>
                        <td className="px-3 py-2 text-right font-mono">
                          {group.calculatedPrice !== null ? (
                            <span className={group.isCalculated ? "text-blue-600" : ""}>
                              {group.calculatedPrice.toFixed(2)}
                            </span>
                          ) : (
                            <span className="text-muted-foreground">-</span>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              <p className="mt-2 text-xs text-muted-foreground">
                Blue prices are calculated based on the selected default price group and multipliers.
              </p>
            </div>
          )}
        </>
      )}
      <div className="mb-4">
        <Label htmlFor="supplierName">Supplier Name</Label>
        <Input
          id="supplierName"
          {...register("supplierName")}
          aria-invalid={errors.supplierName ? "true" : "false"}
        />
        {errors.supplierName && (
          <p className="text-red-500 text-sm mt-1" role="alert">
            {errors.supplierName.message}
          </p>
        )}
      </div>
      <div className="mb-4">
        <Label htmlFor="supplierLink">Supplier Link</Label>
        <Input
          id="supplierLink"
          {...register("supplierLink")}
          aria-invalid={errors.supplierLink ? "true" : "false"}
        />
        {errors.supplierLink && (
          <p className="text-red-500 text-sm mt-1" role="alert">
            {errors.supplierLink.message}
          </p>
        )}
      </div>
      <div className="mb-4">
        <Label htmlFor="priceComment">Price Comment</Label>
        <Input
          id="priceComment"
          {...register("priceComment")}
          aria-invalid={errors.priceComment ? "true" : "false"}
        />
        {errors.priceComment && (
          <p className="text-red-500 text-sm mt-1" role="alert">
            {errors.priceComment.message}
          </p>
        )}
      </div>
      <div className="mb-4">
        <Label htmlFor="stock">Stock</Label>
        <Input
          id="stock"
          type="number"
          {...register("stock", { valueAsNumber: true })}
          aria-invalid={errors.stock ? "true" : "false"}
        />
        {errors.stock && (
          <p className="text-red-500 text-sm mt-1" role="alert">
            {errors.stock.message}
          </p>
        )}
      </div>
      <div className="mb-4">
        <Label className="mb-2 block">Catalogs</Label>
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="outline" className="w-full justify-between">
              {selectedCatalogIds.length > 0
                ? selectedCatalogSummary
                : "Select catalogs"}
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent className="w-56">
            {catalogsLoading ? (
              <div className="p-2 text-sm text-muted-foreground">Loading...</div>
            ) : catalogsError ? (
              <div className="p-2 text-sm text-red-500">{catalogsError}</div>
            ) : catalogs.length === 0 ? (
              <div className="p-2 text-sm text-muted-foreground">No catalogs found</div>
            ) : (
              catalogs.map((catalog: CatalogRecord) => (
                <DropdownMenuCheckboxItem
                  key={catalog.id}
                  checked={selectedCatalogIds.includes(catalog.id)}
                  onCheckedChange={() => toggleCatalog(catalog.id)}
                >
                  {catalog.name}
                </DropdownMenuCheckboxItem>
              ))
            )}
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
      <div className="mb-4">
        <Label className="mb-2 block">Categories</Label>
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="outline" className="w-full justify-between" disabled={selectedCatalogIds.length === 0}>
              {selectedCategoryIds.length > 0
                ? `${selectedCategoryIds.length} categor${selectedCategoryIds.length === 1 ? 'y' : 'ies'} selected`
                : selectedCatalogIds.length === 0
                ? "Select a catalog first"
                : "Select categories"}
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent className="w-56">
            {categoriesLoading ? (
              <div className="p-2 text-sm text-muted-foreground">Loading...</div>
            ) : categories.length === 0 ? (
              <div className="p-2 text-sm text-muted-foreground">No categories found</div>
            ) : (
              <>
                <div className="p-2">
                  <div className="relative">
                    <Input
                      value={categoryQuery}
                      onChange={(event: React.ChangeEvent<HTMLInputElement>) => setCategoryQuery(event.target.value)}
                      placeholder="Search categories..."
                      className="h-8 pr-8"
                    />
                    {categoryQuery && (
                      <Button
                        type="button"
                        onClick={() => setCategoryQuery("")}
                        className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-white"
