                    )}
                  </div>
                </div>
                {filteredCategories.length === 0 ? (
                  <div className="px-2 pb-2 text-sm text-muted-foreground">No matching categories</div>
                ) : (
                  filteredCategories.map((category: ProductCategory) => (
