  defaultPriceGroupId?: string | null;
  priceGroupIds?: string[] | null;
  createdAt: Date;
  updatedAt: Date;
  languageIds?: string[] | null;
  languages?: { languageId: string }[];
};

type CatalogDocument = Omit<CatalogRecord, "languageIds"> & {
  languageIds?: string[] | null;
};

type ProductDocument = {
  _id: string;
  id: string;
  sku: string | null;
  baseProductId?: string | null;
  defaultPriceGroupId?: string | null;
  ean?: string | null;
  gtin?: string | null;
  asin?: string | null;
  name_en: string | null;
  name_pl: string | null;
  name_de: string | null;
  description_en: string | null;
  description_pl: string | null;
  description_de: string | null;
  supplierName: string | null;
  supplierLink: string | null;
  priceComment: string | null;
  stock: number | null;
  price: number | null;
  sizeLength: number | null;
  sizeWidth: number | null;
  weight: number | null;
  length: number | null;
  imageLinks?: string[] | null;
  createdAt: Date;
  updatedAt: Date;
  images: Array<{
    productId: string;
    imageFileId: string;
    assignedAt: Date;
    imageFile: ImageFileRecord;
  }>;
  catalogs: Array<{
    productId: string;
    catalogId: string;
    assignedAt: Date;
    catalog: CatalogDocument;
  }>;
};

const PRODUCT_COLLECTION = "products";

type ProductInput = {
  id: string;
  sku: string | null;
  baseProductId?: string | null;
  defaultPriceGroupId?: string | null;
  ean?: string | null;
  gtin?: string | null;
  asin?: string | null;
  name_en: string | null;
  name_pl: string | null;
  name_de: string | null;
  description_en: string | null;
  description_pl: string | null;
  description_de: string | null;
  supplierName: string | null;
  supplierLink: string | null;
  priceComment: string | null;
  stock: number | null;
  price: number | null;
  sizeLength: number | null;
  sizeWidth: number | null;
  weight: number | null;
  length: number | null;
  imageLinks?: string[] | null;
  createdAt: Date;
  updatedAt: Date;
  images: Array<{
    productId: string;
    imageFileId: string;
    assignedAt: Date;
    imageFile: ImageFileInput;
  }>;
  catalogs: Array<{
    productId: string;
    catalogId: string;
    assignedAt: Date;
    catalog: CatalogInput;
  }>;
