const toImageFileRecord = (imageFile: ImageFileInput): ImageFileRecord => ({
  id: imageFile.id,
  filename: imageFile.filename,
  filepath: imageFile.filepath,
  mimetype: imageFile.mimetype,
  size: imageFile.size,
  width: imageFile.width ?? null,
  height: imageFile.height ?? null,
  tags: imageFile.tags ?? [],
  createdAt: imageFile.createdAt,
  updatedAt: imageFile.updatedAt,
});

const toCatalogDocument = (catalog: CatalogInput): CatalogDocument => ({
  id: catalog.id,
  name: catalog.name,
  description: catalog.description ?? null,
  isDefault: catalog.isDefault,
  defaultLanguageId: catalog.defaultLanguageId ?? null,
  defaultPriceGroupId: catalog.defaultPriceGroupId ?? null,
  createdAt: catalog.createdAt,
  updatedAt: catalog.updatedAt,
  languageIds: Array.isArray(catalog.languageIds)
    ? catalog.languageIds
    : catalog.languages?.map((entry) => entry.languageId) ?? [],
  priceGroupIds: Array.isArray(catalog.priceGroupIds)
    ? catalog.priceGroupIds
    : [],
});

const buildProductDocument = (product: ProductInput): ProductDocument => ({
  _id: product.id,
  id: product.id,
  sku: product.sku ?? null,
  baseProductId: product.baseProductId ?? null,
  defaultPriceGroupId: product.defaultPriceGroupId ?? null,
  ean: product.ean ?? null,
  gtin: product.gtin ?? null,
  asin: product.asin ?? null,
  name_en: product.name_en ?? null,
  name_pl: product.name_pl ?? null,
  name_de: product.name_de ?? null,
  description_en: product.description_en ?? null,
  description_pl: product.description_pl ?? null,
  description_de: product.description_de ?? null,
  supplierName: product.supplierName ?? null,
  supplierLink: product.supplierLink ?? null,
  priceComment: product.priceComment ?? null,
  stock: product.stock ?? null,
  price: product.price ?? null,
  sizeLength: product.sizeLength ?? null,
  sizeWidth: product.sizeWidth ?? null,
  weight: product.weight ?? null,
  length: product.length ?? null,
  imageLinks: Array.isArray(product.imageLinks) ? product.imageLinks : [],
  createdAt: product.createdAt,
  updatedAt: product.updatedAt,
  images: product.images.map((image) => ({
    productId: image.productId,
    imageFileId: image.imageFileId,
    assignedAt: image.assignedAt,
    imageFile: toImageFileRecord(image.imageFile),
  })),
  catalogs: product.catalogs.map((entry) => ({
    productId: entry.productId,
    catalogId: entry.catalogId,
    assignedAt: entry.assignedAt,
    catalog: toCatalogDocument(entry.catalog),
  })),
});

export async function getProductMigrationTotal(direction: MigrationDirection) {
  if (direction === "prisma-to-mongo") {
    return prisma.product.count();
  }
  const mongo = await getMongoDb();
  return mongo.collection<ProductDocument>(PRODUCT_COLLECTION).countDocuments();
}

export async function migrateProductBatch({
  direction,
  dryRun = false,
  cursor,
  batchSize = 50,
}: {
  direction: MigrationDirection;
  dryRun?: boolean | undefined;
  cursor?: string | null | undefined;
  batchSize?: number | undefined;
}): Promise<MigrationBatchResult> {
  if (direction === "prisma-to-mongo") {
    const mongo = await getMongoDb();
    const products = await prisma.product.findMany({
      ...(cursor && { where: { id: { gt: cursor } } }),
      orderBy: { id: "asc" },
      take: batchSize,
      include: {
        images: { include: { imageFile: true } },
        catalogs: {
          include: {
            catalog: {
              include: { languages: { select: { languageId: true } } },
            },
          },
        },
      },
    });
    const docs = products.map(buildProductDocument);
    if (!dryRun) {
      await mongo.collection<ProductDocument>(PRODUCT_COLLECTION).bulkWrite(
        docs.map((doc) => ({
          replaceOne: {
            filter: { _id: doc._id },
            replacement: doc,
            upsert: true,
          },
        })),
        { ordered: false }
      );
    }
    const nextCursor =
      products.length === batchSize
        ? products[products.length - 1]?.id ?? null
        : null;
    return {
      direction,
      productsProcessed: docs.length,
      productsUpserted: dryRun ? 0 : docs.length,
      nextCursor,
      missingImageFileIds: [],
      missingCatalogIds: [],
    };
  }

  const mongo = await getMongoDb();
  const mongoDocs: WithId<ProductDocument>[] = await mongo
    .collection<ProductDocument>(PRODUCT_COLLECTION)
    .find(cursor ? { _id: { $gt: cursor } } : {})
    .sort({ _id: 1 })
    .limit(batchSize)
    .toArray();
  const imageFileMap = new Map<string, ImageFileRecord>();
  const catalogMap = new Map<string, CatalogDocument>();
  for (const doc of mongoDocs) {
    const images = Array.isArray(doc.images) ? doc.images : [];
    for (const image of images) {
      imageFileMap.set(image.imageFileId, image.imageFile);
    }
    const catalogs = Array.isArray(doc.catalogs) ? doc.catalogs : [];
    for (const catalog of catalogs) {
      catalogMap.set(catalog.catalogId, catalog.catalog);
    }
  }

  if (!dryRun) {
    for (const [id, imageFile] of Array.from(imageFileMap.entries())) {
      await prisma.imageFile.upsert({
        where: { id },
        update: {
          filename: imageFile.filename,
          filepath: imageFile.filepath,
          mimetype: imageFile.mimetype,
          size: imageFile.size,
          width: imageFile.width ?? null,
          height: imageFile.height ?? null,
        },
        create: {
          id,
          filename: imageFile.filename,
          filepath: imageFile.filepath,
          mimetype: imageFile.mimetype,
          size: imageFile.size,
          width: imageFile.width ?? null,
          height: imageFile.height ?? null,
        },
      });
    }
    for (const [id, catalog] of Array.from(catalogMap.entries())) {
      await prisma.catalog.upsert({
        where: { id },
        update: {
          name: catalog.name,
          description: catalog.description ?? null,
          isDefault: catalog.isDefault ?? false,
          defaultLanguageId: catalog.defaultLanguageId ?? null,
        },
        create: {
          id,
          name: catalog.name,
          description: catalog.description ?? null,
          isDefault: catalog.isDefault ?? false,
          defaultLanguageId: catalog.defaultLanguageId ?? null,
        },
      });
      const languageIds: string[] = [];
      const rawLanguageIds = catalog.languageIds ?? [];
      if (Array.isArray(rawLanguageIds)) {
        for (const languageId of rawLanguageIds) {
          if (typeof languageId === "string") {
            languageIds.push(languageId);
          }
        }
      }
      if (languageIds.length > 0) {
        const existingLanguages = await prisma.language.findMany({
          where: { id: { in: languageIds } },
          select: { id: true },
        });
        const validLanguageIds = new Set(
          existingLanguages.map((entry) => entry.id)
        );
        await prisma.catalogLanguage.deleteMany({ where: { catalogId: id } });
        const filteredLanguageIds: string[] = [];
        for (const languageId of languageIds) {
          if (validLanguageIds.has(languageId)) {
            filteredLanguageIds.push(languageId);
          }
        }
        if (filteredLanguageIds.length > 0) {
          await prisma.catalogLanguage.createMany({
            data: filteredLanguageIds.map((languageId) => ({
              catalogId: id,
              languageId,
            })),
            skipDuplicates: true,
          });
        }
        const nextDefaultLanguageId =
          catalog.defaultLanguageId &&
          filteredLanguageIds.includes(catalog.defaultLanguageId)
            ? catalog.defaultLanguageId
            : filteredLanguageIds[0] ?? null;
        await prisma.catalog.update({
          where: { id },
          data: { defaultLanguageId: nextDefaultLanguageId },
        });
      } else {
        await prisma.catalog.update({
          where: { id },
          data: { defaultLanguageId: null },
        });
      }
    }
  }

  const imageFileIds = new Set(imageFileMap.keys());
  const catalogIds = new Set(catalogMap.keys());
  const existingImages = await prisma.imageFile.findMany({
    where: { id: { in: Array.from(imageFileIds) } },
    select: { id: true },
  });
  const existingCatalogs = await prisma.catalog.findMany({
    where: { id: { in: Array.from(catalogIds) } },
    select: { id: true },
  });
  const existingImageIds = new Set(existingImages.map((img) => img.id));
  const existingCatalogIds = new Set(existingCatalogs.map((cat) => cat.id));
  const missingImageFileIds = Array.from(imageFileIds).filter(
    (id) => !existingImageIds.has(id)
  );
  const missingCatalogIds = Array.from(catalogIds).filter(
    (id) => !existingCatalogIds.has(id)
  );

  if (!dryRun) {
    for (const doc of mongoDocs) {
      await prisma.product.upsert({
        where: { id: doc.id ?? doc._id },
        update: {
          ...(doc.sku !== undefined && { sku: doc.sku }),
          ...(doc.baseProductId !== undefined && {
            baseProductId: doc.baseProductId,
          }),
          ...(doc.defaultPriceGroupId !== undefined && {
            defaultPriceGroupId: doc.defaultPriceGroupId,
          }),
          ...(doc.ean !== undefined && { ean: doc.ean }),
          ...(doc.gtin !== undefined && { gtin: doc.gtin }),
          ...(doc.asin !== undefined && { asin: doc.asin }),
          ...(doc.name_en !== undefined && { name_en: doc.name_en }),
          ...(doc.name_pl !== undefined && { name_pl: doc.name_pl }),
          ...(doc.name_de !== undefined && { name_de: doc.name_de }),
          ...(doc.description_en !== undefined && {
            description_en: doc.description_en,
          }),
          ...(doc.description_pl !== undefined && {
            description_pl: doc.description_pl,
          }),
          ...(doc.description_de !== undefined && {
            description_de: doc.description_de,
          }),
          ...(doc.supplierName !== undefined && {
            supplierName: doc.supplierName,
          }),
          ...(doc.supplierLink !== undefined && {
            supplierLink: doc.supplierLink,
          }),
          ...(doc.priceComment !== undefined && {
            priceComment: doc.priceComment,
          }),
          ...(doc.stock !== undefined && { stock: doc.stock }),
          ...(doc.price !== undefined && { price: doc.price }),
          ...(doc.sizeLength !== undefined && { sizeLength: doc.sizeLength }),
          ...(doc.sizeWidth !== undefined && { sizeWidth: doc.sizeWidth }),
          ...(doc.weight !== undefined && { weight: doc.weight }),
          ...(doc.length !== undefined && { length: doc.length }),
          imageLinks: Array.isArray(doc.imageLinks) ? doc.imageLinks : [],
          createdAt: doc.createdAt ?? new Date(),
          updatedAt: doc.updatedAt ?? new Date(),
        },
        create: {
          id: doc.id ?? doc._id,
          ...(doc.sku !== undefined && { sku: doc.sku }),
          ...(doc.baseProductId !== undefined && {
            baseProductId: doc.baseProductId,
          }),
          ...(doc.defaultPriceGroupId !== undefined && {
            defaultPriceGroupId: doc.defaultPriceGroupId,
          }),
          ...(doc.ean !== undefined && { ean: doc.ean }),
          ...(doc.gtin !== undefined && { gtin: doc.gtin }),
          ...(doc.asin !== undefined && { asin: doc.asin }),
          ...(doc.name_en !== undefined && { name_en: doc.name_en }),
          ...(doc.name_pl !== undefined && { name_pl: doc.name_pl }),
          ...(doc.name_de !== undefined && { name_de: doc.name_de }),
          ...(doc.description_en !== undefined && {
            description_en: doc.description_en,
          }),
          ...(doc.description_pl !== undefined && {
            description_pl: doc.description_pl,
          }),
          ...(doc.description_de !== undefined && {
            description_de: doc.description_de,
          }),
          ...(doc.supplierName !== undefined && {
            supplierName: doc.supplierName,
          }),
          ...(doc.supplierLink !== undefined && {
            supplierLink: doc.supplierLink,
          }),
          ...(doc.priceComment !== undefined && {
            priceComment: doc.priceComment,
          }),
          ...(doc.stock !== undefined && { stock: doc.stock }),
          ...(doc.price !== undefined && { price: doc.price }),
          ...(doc.sizeLength !== undefined && { sizeLength: doc.sizeLength }),
          ...(doc.sizeWidth !== undefined && { sizeWidth: doc.sizeWidth }),
          ...(doc.weight !== undefined && { weight: doc.weight }),
          ...(doc.length !== undefined && { length: doc.length }),
          imageLinks: Array.isArray(doc.imageLinks) ? doc.imageLinks : [],
          createdAt: doc.createdAt ?? new Date(),
          updatedAt: doc.updatedAt ?? new Date(),
        },
      });

      const validImageIds: string[] = [];
      const images = Array.isArray(doc.images) ? doc.images : [];
      for (const image of images) {
        if (existingImageIds.has(image.imageFileId)) {
          validImageIds.push(image.imageFileId);
        }
      }
      const validCatalogIds: string[] = [];
      const catalogs = Array.isArray(doc.catalogs) ? doc.catalogs : [];
      for (const catalog of catalogs) {
        if (existingCatalogIds.has(catalog.catalogId)) {
          validCatalogIds.push(catalog.catalogId);
        }
      }

      await prisma.productImage.deleteMany({ where: { productId: doc.id } });
      if (validImageIds.length > 0) {
        await prisma.productImage.createMany({
          data: validImageIds.map((imageFileId) => ({
            productId: doc.id,
            imageFileId,
          })),
          skipDuplicates: true,
        });
      }

      await prisma.productCatalog.deleteMany({ where: { productId: doc.id } });
      if (validCatalogIds.length > 0) {
        await prisma.productCatalog.createMany({
          data: validCatalogIds.map((catalogId) => ({
            productId: doc.id,
            catalogId,
          })),
          skipDuplicates: true,
        });
      }
    }
  }

  const nextCursor =
    mongoDocs.length === batchSize
      ? mongoDocs[mongoDocs.length - 1]?._id ?? null
      : null;
  return {
    direction,
    productsProcessed: mongoDocs.length,
    productsUpserted: dryRun ? 0 : mongoDocs.length,
    nextCursor,
    missingImageFileIds,
    missingCatalogIds,
  };
}

import "server-only";

import { randomUUID } from "crypto";
import type { Filter, WithId } from "mongodb";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { conflictError } from "@/shared/errors/app-error";
import type { ProductRecord, ProductWithImages } from "@/features/products/types";
import { mongoCatalogRepository } from "@/features/products/services/catalog-repository/mongo-catalog-repository";
import { mongoImageFileRepository } from "@/features/files/server";
import type {
  CreateProductInput,
  ProductFilters,
  ProductRepository,
  UpdateProductInput,
} from "@/features/products/types/services/product-repository";

type ProductDocument = ProductRecord & {
  _id: string;
  images?: ProductWithImages["images"];
  catalogs?: ProductWithImages["catalogs"];
};

const productCollectionName = "products";

const toProductResponse = (doc: WithId<ProductDocument>): ProductWithImages => ({
  id: doc.id ?? doc._id,
  sku: doc.sku ?? null,
  baseProductId: doc.baseProductId ?? null,
  defaultPriceGroupId: doc.defaultPriceGroupId ?? null,
  ean: doc.ean ?? null,
  gtin: doc.gtin ?? null,
  asin: doc.asin ?? null,
  name_en: doc.name_en ?? null,
  name_pl: doc.name_pl ?? null,
  name_de: doc.name_de ?? null,
  description_en: doc.description_en ?? null,
  description_pl: doc.description_pl ?? null,
  description_de: doc.description_de ?? null,
  supplierName: doc.supplierName ?? null,
  supplierLink: doc.supplierLink ?? null,
  priceComment: doc.priceComment ?? null,
  stock: doc.stock ?? null,
  price: doc.price ?? null,
  sizeLength: doc.sizeLength ?? null,
  sizeWidth: doc.sizeWidth ?? null,
  weight: doc.weight ?? null,
  length: doc.length ?? null,
  parameters: Array.isArray(doc.parameters) ? doc.parameters : [],
  imageLinks: Array.isArray(doc.imageLinks) ? doc.imageLinks : [],
  createdAt: doc.createdAt ?? new Date(),
  updatedAt: doc.updatedAt ?? new Date(),
  images: Array.isArray(doc.images) ? doc.images : [],
  catalogs: Array.isArray(doc.catalogs) ? doc.catalogs : [],
});

const toProductBase = (doc: ProductDocument): ProductRecord => ({
  id: doc.id ?? doc._id,
  sku: doc.sku ?? null,
  baseProductId: doc.baseProductId ?? null,
  defaultPriceGroupId: doc.defaultPriceGroupId ?? null,
  ean: doc.ean ?? null,
  gtin: doc.gtin ?? null,
  asin: doc.asin ?? null,
  name_en: doc.name_en ?? null,
  name_pl: doc.name_pl ?? null,
  name_de: doc.name_de ?? null,
  description_en: doc.description_en ?? null,
  description_pl: doc.description_pl ?? null,
  description_de: doc.description_de ?? null,
  supplierName: doc.supplierName ?? null,
  supplierLink: doc.supplierLink ?? null,
  priceComment: doc.priceComment ?? null,
  stock: doc.stock ?? null,
  price: doc.price ?? null,
  sizeLength: doc.sizeLength ?? null,
  sizeWidth: doc.sizeWidth ?? null,
  weight: doc.weight ?? null,
  length: doc.length ?? null,
  parameters: Array.isArray(doc.parameters) ? doc.parameters : [],
  imageLinks: Array.isArray(doc.imageLinks) ? doc.imageLinks : [],
  createdAt: doc.createdAt ?? new Date(),
  updatedAt: doc.updatedAt ?? new Date(),
});

const buildSearchFilter = (filters: ProductFilters): Filter<ProductDocument> => {
  const filter: Filter<ProductDocument> = {};

  if (filters.sku) {
    filter.sku = { $regex: filters.sku, $options: "i" };
  }

  if (filters.search) {
    const regex = { $regex: filters.search, $options: "i" };
    // If a specific language is selected, only search in that language's name field
    if (filters.searchLanguage) {
      // searchLanguage is like "name_en", "name_pl", "name_de"
      filter.$or = [{ [filters.searchLanguage]: regex }];
    } else {
      // Search all language fields
      filter.$or = [
        { name_en: regex },
        { name_pl: regex },
        { name_de: regex },
        { description_en: regex },
        { description_pl: regex },
        { description_de: regex },
      ];
    }
  }

  if (filters.minPrice || filters.maxPrice) {
    filter.price = {};
    if (filters.minPrice) {
      filter.price.$gte = parseInt(filters.minPrice, 10);
    }
    if (filters.maxPrice) {
      filter.price.$lte = parseInt(filters.maxPrice, 10);
    }
  }

  if (filters.startDate || filters.endDate) {
    filter.createdAt = {};
    if (filters.startDate) {
      filter.createdAt.$gte = new Date(filters.startDate);
    }
    if (filters.endDate) {
      filter.createdAt.$lte = new Date(filters.endDate);
    }
  }

  if (filters.catalogId) {
    if (filters.catalogId === "unassigned") {
      filter.catalogs = { $size: 0 };
    } else {
      filter.catalogs = { $elemMatch: { catalogId: filters.catalogId } };
    }
  }

  return filter;
};

export const mongoProductRepository: ProductRepository = {
  async getProducts(filters: ProductFilters) {
    const db = await getMongoDb();
    const page = filters.page ? parseInt(filters.page, 10) : undefined;
    const pageSize = filters.pageSize ? parseInt(filters.pageSize, 10) : undefined;
    const skip = page && pageSize ? (page - 1) * pageSize : undefined;
    const limit = pageSize;

    let cursor = db
      .collection<ProductDocument>(productCollectionName)
      .find(buildSearchFilter(filters))
      .sort({ createdAt: -1 });

    if (skip !== undefined) {
      cursor = cursor.skip(skip);
    }
    if (limit !== undefined) {
      cursor = cursor.limit(limit);
    }

    const docs = await cursor.toArray();
    return docs.map(toProductResponse);
  },

  async countProducts(filters: ProductFilters) {
    const db = await getMongoDb();
    return db
      .collection<ProductDocument>(productCollectionName)
      .countDocuments(buildSearchFilter(filters));
  },

  async getProductById(id: string) {
    const db = await getMongoDb();
    const doc = await db
      .collection<ProductDocument>(productCollectionName)
      .findOne({ $or: [{ _id: id }, { id }] });
    return doc ? toProductResponse({ ...doc, _id: doc._id }) : null;
  },

  async getProductBySku(sku: string) {
    const db = await getMongoDb();
    const doc = await db
      .collection<ProductDocument>(productCollectionName)
      .findOne({ sku });
    return doc ? toProductBase(doc) : null;
  },

  async findProductByBaseId(baseProductId: string) {
    const db = await getMongoDb();
    const doc = await db
      .collection<ProductDocument>(productCollectionName)
      .findOne({ baseProductId });
    return doc ? toProductBase(doc) : null;
  },

  async createProduct(data: CreateProductInput) {
    const db = await getMongoDb();
    const now = new Date();
    const id = randomUUID();
    if (data.sku) {
      const existing = await db
        .collection<ProductDocument>(productCollectionName)
        .findOne({ sku: data.sku });
      if (existing) {
        throw conflictError("A product with this SKU already exists.", {
          sku: data.sku,
          productId: existing.id ?? existing._id,
        });
      }
    }
    const document: ProductDocument = {
      _id: id,
      id,
      sku: typeof data.sku === "string" ? data.sku : null,
      baseProductId:
        typeof data.baseProductId === "string" ? data.baseProductId : null,
      defaultPriceGroupId:
        typeof data.defaultPriceGroupId === "string"
          ? data.defaultPriceGroupId
          : null,
      ean: typeof data.ean === "string" ? data.ean : null,
      gtin: typeof data.gtin === "string" ? data.gtin : null,
      asin: typeof data.asin === "string" ? data.asin : null,
      name_en: typeof data.name_en === "string" ? data.name_en : null,
      name_pl: typeof data.name_pl === "string" ? data.name_pl : null,
      name_de: typeof data.name_de === "string" ? data.name_de : null,
      description_en:
        typeof data.description_en === "string" ? data.description_en : null,
      description_pl:
        typeof data.description_pl === "string" ? data.description_pl : null,
      description_de:
        typeof data.description_de === "string" ? data.description_de : null,
      supplierName:
        typeof data.supplierName === "string" ? data.supplierName : null,
      supplierLink:
        typeof data.supplierLink === "string" ? data.supplierLink : null,
      priceComment:
        typeof data.priceComment === "string" ? data.priceComment : null,
      stock: typeof data.stock === "number" ? data.stock : null,
      price: typeof data.price === "number" ? data.price : null,
      sizeLength: typeof data.sizeLength === "number" ? data.sizeLength : null,
      sizeWidth: typeof data.sizeWidth === "number" ? data.sizeWidth : null,
      weight: typeof data.weight === "number" ? data.weight : null,
      length: typeof data.length === "number" ? data.length : null,
      parameters: Array.isArray(data.parameters) ? data.parameters.map(p => ({ parameterId: p.parameterId, value: p.value || "" })) : [],
      imageLinks: Array.isArray(data.imageLinks) ? data.imageLinks : [],
      createdAt: now,
      updatedAt: now,
      images: [],
      catalogs: [],
    };
    await db
      .collection<ProductDocument>(productCollectionName)
      .insertOne(document);
    return toProductBase(document);
  },

  async updateProduct(id: string, data: UpdateProductInput) {
    const db = await getMongoDb();
    const updateDoc: Partial<ProductDocument> = {
      updatedAt: new Date(),
      ...(data.sku !== undefined ? { sku: data.sku ?? null } : null),
      ...(data.baseProductId !== undefined
        ? { baseProductId: data.baseProductId ?? null }
        : null),
      ...(data.defaultPriceGroupId !== undefined
        ? { defaultPriceGroupId: data.defaultPriceGroupId ?? null }
        : null),
      ...(data.ean !== undefined ? { ean: data.ean ?? null } : null),
      ...(data.gtin !== undefined ? { gtin: data.gtin ?? null } : null),
      ...(data.asin !== undefined ? { asin: data.asin ?? null } : null),
      ...(data.name_en !== undefined ? { name_en: data.name_en ?? null } : null),
      ...(data.name_pl !== undefined ? { name_pl: data.name_pl ?? null } : null),
      ...(data.name_de !== undefined ? { name_de: data.name_de ?? null } : null),
      ...(data.description_en !== undefined
        ? { description_en: data.description_en ?? null }
        : null),
      ...(data.description_pl !== undefined
        ? { description_pl: data.description_pl ?? null }
        : null),
      ...(data.description_de !== undefined
        ? { description_de: data.description_de ?? null }
        : null),
      ...(data.supplierName !== undefined
        ? { supplierName: data.supplierName ?? null }
        : null),
      ...(data.supplierLink !== undefined
        ? { supplierLink: data.supplierLink ?? null }
        : null),
      ...(data.priceComment !== undefined
        ? { priceComment: data.priceComment ?? null }
        : null),
      ...(data.stock !== undefined ? { stock: data.stock ?? null } : null),
      ...(data.price !== undefined ? { price: data.price ?? null } : null),
      ...(data.sizeLength !== undefined
        ? { sizeLength: data.sizeLength ?? null }
        : null),
      ...(data.sizeWidth !== undefined
        ? { sizeWidth: data.sizeWidth ?? null }
        : null),
      ...(data.weight !== undefined ? { weight: data.weight ?? null } : null),
      ...(data.length !== undefined ? { length: data.length ?? null } : null),
      ...(data.parameters !== undefined
        ? {
            parameters: Array.isArray(data.parameters) ? data.parameters.map(p => ({ parameterId: p.parameterId, value: p.value || "" })) : [],
          }
        : null),
      ...(data.imageLinks !== undefined
        ? {
            imageLinks: Array.isArray(data.imageLinks)
              ? data.imageLinks
              : [],
          }
        : null),
    };
    const result = await db
      .collection<ProductDocument>(productCollectionName)
      .findOneAndUpdate(
        { $or: [{ _id: id }, { id }] },
        { $set: updateDoc },
        { returnDocument: "after" }
      );
    if (!result) return null;
    return toProductBase({
      ...(result as ProductDocument),
      id: (result as ProductDocument).id ?? id,
    });
  },

  async deleteProduct(id: string) {
    const db = await getMongoDb();
    const result = await db
      .collection<ProductDocument>(productCollectionName)
      .findOneAndDelete({ $or: [{ _id: id }, { id }] });
    if (!result) return null;
    return toProductBase({
      ...(result as ProductDocument),
      id: (result as ProductDocument).id ?? id,
    });
  },

  async duplicateProduct(id: string, sku: string) {
    const db = await getMongoDb();
    const existing = await db
      .collection<ProductDocument>(productCollectionName)
      .findOne({ $or: [{ _id: id }, { id }] });
    if (!existing) return null;

    const skuExists = await db
      .collection<ProductDocument>(productCollectionName)
      .findOne({ sku });
    if (skuExists) {
      throw conflictError("A product with this SKU already exists.", {
        sku,
        productId: skuExists.id ?? skuExists._id,
      });
    }

    const now = new Date();
    const duplicatedId = randomUUID();
    const document: ProductDocument = {
      _id: duplicatedId,
      id: duplicatedId,
      sku,
      baseProductId: null,
      defaultPriceGroupId: existing.defaultPriceGroupId ?? null,
      ean: existing.ean ?? null,
      gtin: existing.gtin ?? null,
      asin: existing.asin ?? null,
      name_en: existing.name_en ?? null,
      name_pl: existing.name_pl ?? null,
      name_de: existing.name_de ?? null,
      description_en: existing.description_en ?? null,
      description_pl: existing.description_pl ?? null,
      description_de: existing.description_de ?? null,
      supplierName: existing.supplierName ?? null,
      supplierLink: existing.supplierLink ?? null,
      priceComment: existing.priceComment ?? null,
      stock: existing.stock ?? null,
      price: existing.price ?? null,
      sizeLength: existing.sizeLength ?? null,
      sizeWidth: existing.sizeWidth ?? null,
      weight: existing.weight ?? null,
      length: existing.length ?? null,
      parameters: Array.isArray(existing.parameters) ? existing.parameters : [],
      imageLinks: Array.isArray(existing.imageLinks) ? existing.imageLinks : [],
      createdAt: now,
      updatedAt: now,
      images: [],
      catalogs: [],
    };

    await db
      .collection<ProductDocument>(productCollectionName)
      .insertOne(document);
    return toProductBase(document);
  },

  async addProductImages(productId: string, imageFileIds: string[]) {
    if (imageFileIds.length === 0) return;
    const db = await getMongoDb();
    const imageFiles = await mongoImageFileRepository.findImageFilesByIds(
      imageFileIds
    );
    const now = new Date();
    const incoming = imageFiles.map((imageFile) => ({
      productId,
      imageFileId: imageFile.id,
      assignedAt: now,
      imageFile,
    }));
    const product = await db
      .collection<ProductDocument>(productCollectionName)
      .findOne({ $or: [{ _id: productId }, { id: productId }] });
    const existing = Array.isArray(product?.images) ? product.images : [];
    const merged = [
      ...existing.filter(
        (entry) =>
          !incoming.some(
            (next) => next.imageFileId === entry.imageFileId
          )
      ),
      ...incoming,
    ];
    await db
      .collection<ProductDocument>(productCollectionName)
      .updateOne(
        { $or: [{ _id: productId }, { id: productId }] },
        { $set: { images: merged, updatedAt: new Date() } }
      );
  },

  async replaceProductCatalogs(productId: string, catalogIds: string[]) {
    const db = await getMongoDb();
    if (catalogIds.length === 0) {
      await db
        .collection<ProductDocument>(productCollectionName)
        .updateOne(
          { $or: [{ _id: productId }, { id: productId }] },
          { $set: { catalogs: [], updatedAt: new Date() } }
        );
      return;
    }
    const uniqueIds = Array.from(new Set(catalogIds));
    const catalogs = await mongoCatalogRepository.getCatalogsByIds(uniqueIds);
    const now = new Date();
    const catalogEntries = catalogs.map((catalog) => ({
      productId,
      catalogId: catalog.id,
      assignedAt: now,
      catalog,
    }));
    await db
      .collection<ProductDocument>(productCollectionName)
      .updateOne(
        { $or: [{ _id: productId }, { id: productId }] },
        { $set: { catalogs: catalogEntries, updatedAt: new Date() } }
      );
  },

  async replaceProductCategories(productId: string, categoryIds: string[]) {
    const db = await getMongoDb();
    if (categoryIds.length === 0) {
      await db
        .collection<ProductDocument>(productCollectionName)
        .updateOne(
          { $or: [{ _id: productId }, { id: productId }] },
          { $set: { categories: [], updatedAt: new Date() } }
        );
      return;
    }
    const uniqueIds = Array.from(new Set(categoryIds));
    const categories = await db
      .collection("product_categories")
      .find({ id: { $in: uniqueIds } })
      .toArray();
    const now = new Date();
    const categoryEntries = categories.map((category) => ({
      productId,
      categoryId: (category as unknown as { id: string }).id,
      assignedAt: now,
    }));
    await db
      .collection<ProductDocument>(productCollectionName)
      .updateOne(
        { $or: [{ _id: productId }, { id: productId }] },
        { $set: { categories: categoryEntries, updatedAt: new Date() } }
      );
  },

  async replaceProductTags(productId: string, tagIds: string[]) {
    const db = await getMongoDb();
    if (tagIds.length === 0) {
      await db
        .collection<ProductDocument>(productCollectionName)
        .updateOne(
          { $or: [{ _id: productId }, { id: productId }] },
          { $set: { tags: [], updatedAt: new Date() } }
        );
      return;
    }
    const uniqueIds = Array.from(new Set(tagIds));
    const tags = await db
      .collection("product_tags")
      .find({ id: { $in: uniqueIds } })
      .toArray();
    const now = new Date();
    const tagEntries = tags.map((tag) => ({
      productId,
      tagId: (tag as unknown as { id: string }).id,
      assignedAt: now,
    }));
    await db
      .collection<ProductDocument>(productCollectionName)
      .updateOne(
        { $or: [{ _id: productId }, { id: productId }] },
        { $set: { tags: tagEntries, updatedAt: new Date() } }
      );
  },

  async removeProductImage(productId: string, imageFileId: string) {
    const db = await getMongoDb();
    await db
      .collection<ProductDocument>(productCollectionName)
      .updateOne(
        { $or: [{ _id: productId }, { id: productId }] },
        {
          $pull: {
            images: {
              imageFileId,
            },
          },
        }
      );
  },

  async countProductsByImageFileId(imageFileId: string) {
    const db = await getMongoDb();
    return db
      .collection<ProductDocument>(productCollectionName)
      .countDocuments({ "images.imageFileId": imageFileId });
  },
};

import "server-only";

import { Prisma } from "@prisma/client";
import prisma from "@/shared/lib/db/prisma";
import { conflictError } from "@/shared/errors/app-error";
import type { CatalogRecord, ProductRecord } from "@/features/products/types";
import type { ImageFileRecord } from "@/shared/types/files";
import type { ProductParameterValue } from "@/features/products/types";
import type {
  CreateProductInput,
  ProductFilters,
  ProductRepository,
  UpdateProductInput,
} from "@/features/products/types/services/product-repository";

// Helper to remove undefined keys for exactOptionalPropertyTypes compliance
function removeUndefined<T extends object>(obj: T): T {
  const newObj = { ...obj };
  Object.keys(newObj).forEach((key) => {
    if (newObj[key as keyof T] === undefined) {
      delete newObj[key as keyof T];
    }
  });
  return newObj;
}

const buildProductWhere = (filters: ProductFilters) => {
  const where: Prisma.ProductWhereInput = {};

  if (filters.sku) {
    where.sku = {
      contains: filters.sku,
      mode: 'insensitive',
    };
  }

  if (filters.search) {
    // If a specific language is selected, only search in that language's name field
    if (filters.searchLanguage) {
      // searchLanguage is like "name_en", "name_pl", "name_de"
      where.OR = [
        { [filters.searchLanguage]: { contains: filters.search, mode: 'insensitive' } },
      ];
    } else {
      // Search all language fields
      where.OR = [
        { name_en: { contains: filters.search, mode: 'insensitive' } },
        { name_pl: { contains: filters.search, mode: 'insensitive' } },
        { name_de: { contains: filters.search, mode: 'insensitive' } },
        { description_en: { contains: filters.search, mode: 'insensitive' } },
        { description_pl: { contains: filters.search, mode: 'insensitive' } },
        { description_de: { contains: filters.search, mode: 'insensitive' } },
      ];
    }
  }

  if (filters.minPrice !== undefined) {
    where.price = {
      ...(where.price as Prisma.IntFilter),
      gte: typeof filters.minPrice === 'string' ? parseInt(filters.minPrice, 10) : filters.minPrice,
    };
  }
  if (filters.maxPrice !== undefined) {
    where.price = {
      ...(where.price as Prisma.IntFilter),
      lte: typeof filters.maxPrice === 'string' ? parseInt(filters.maxPrice, 10) : filters.maxPrice,
    };
  }
  if (filters.startDate) {
    where.createdAt = {
      ...(where.createdAt as Prisma.DateTimeFilter),
      gte: new Date(filters.startDate),
    };
  }
  if (filters.endDate) {
    where.createdAt = {
      ...(where.createdAt as Prisma.DateTimeFilter),
      lte: new Date(filters.endDate),
    };
  }

  if (filters.catalogId) {
    if (filters.catalogId === "unassigned") {
      where.catalogs = { none: {} };
    } else {
      where.catalogs = { some: { catalogId: filters.catalogId } };
    }
  }

  return where;
};

const toImageFileRecord = (imageFile: {
  id: string;
  filename: string;
  filepath: string;
  mimetype: string;
  size: number;
  width: number | null;
  height: number | null;
  tags: string[] | null;
  createdAt: Date;
  updatedAt: Date;
}): ImageFileRecord => ({
  id: imageFile.id,
  filename: imageFile.filename,
  filepath: imageFile.filepath,
  mimetype: imageFile.mimetype,
  size: imageFile.size,
  width: imageFile.width ?? null,
  height: imageFile.height ?? null,
  tags: imageFile.tags ?? [],
  createdAt: imageFile.createdAt,
  updatedAt: imageFile.updatedAt,
});

const toCatalogRecord = (catalog: {
  id: string;
  name: string;
  description: string | null;
  isDefault: boolean;
  defaultLanguageId: string | null;
  defaultPriceGroupId: string | null;
  priceGroupIds: string[];
  createdAt: Date;
  updatedAt: Date;
  languages?: { languageId: string }[];
}): CatalogRecord => ({
  id: catalog.id,
  name: catalog.name,
  description: catalog.description ?? null,
  isDefault: catalog.isDefault,
  defaultLanguageId: catalog.defaultLanguageId ?? null,
  defaultPriceGroupId: catalog.defaultPriceGroupId ?? null,
  createdAt: catalog.createdAt,
  updatedAt: catalog.updatedAt,
  languageIds: catalog.languages?.map((entry) => entry.languageId) ?? [],
  priceGroupIds: Array.isArray(catalog.priceGroupIds)
    ? catalog.priceGroupIds
    : [],
});

const toProductRecord = (product: {
  id: string;
  sku: string | null;
  baseProductId: string | null;
  defaultPriceGroupId: string | null;
  ean: string | null;
  gtin: string | null;
  asin: string | null;
  name_en: string | null;
  name_pl: string | null;
  name_de: string | null;
  description_en: string | null;
  description_pl: string | null;
  description_de: string | null;
  supplierName: string | null;
  supplierLink: string | null;
  priceComment: string | null;
  stock: number | null;
  price: number | null;
  sizeLength: number | null;
  sizeWidth: number | null;
  weight: number | null;
  length: number | null;
  parameters?: Prisma.JsonValue | null;
  imageLinks: string[];
  createdAt: Date;
  updatedAt: Date;
}): ProductRecord => ({
  id: product.id,
  sku: product.sku ?? null,
  baseProductId: product.baseProductId ?? null,
  defaultPriceGroupId: product.defaultPriceGroupId ?? null,
  ean: product.ean ?? null,
  gtin: product.gtin ?? null,
  asin: product.asin ?? null,
  name_en: product.name_en ?? null,
  name_pl: product.name_pl ?? null,
  name_de: product.name_de ?? null,
  description_en: product.description_en ?? null,
  description_pl: product.description_pl ?? null,
  description_de: product.description_de ?? null,
  supplierName: product.supplierName ?? null,
  supplierLink: product.supplierLink ?? null,
  priceComment: product.priceComment ?? null,
  stock: product.stock ?? null,
  price: product.price ?? null,
  sizeLength: product.sizeLength ?? null,
  sizeWidth: product.sizeWidth ?? null,
  weight: product.weight ?? null,
  length: product.length ?? null,
  parameters: Array.isArray(product.parameters) ? (product.parameters as unknown as ProductParameterValue[]) : [],
  imageLinks: Array.isArray(product.imageLinks) ? product.imageLinks : [],
  createdAt: product.createdAt,
  updatedAt: product.updatedAt,
});

export const prismaProductRepository: ProductRepository = {
  async getProducts(filters: ProductFilters) {
    const where = buildProductWhere(filters);
    const page = filters.page ? parseInt(filters.page, 10) : 1;
    const pageSize = filters.pageSize ? parseInt(filters.pageSize, 10) : 50;

    const products = await prisma.product.findMany({
      where,
      include: {
        images: {
          include: { imageFile: true },
          orderBy: { assignedAt: "desc" },
        },
        catalogs: {
          include: {
            catalog: {
              include: {
                languages: {
                  include: { language: true }
                }
              }
            }
          },
        },
      },
      orderBy: { createdAt: "desc" },
      skip: (page - 1) * pageSize,
      take: pageSize,
    });

    return products.map((product) => ({
      ...toProductRecord(product),
      images: product.images.map((image) => ({
        productId: image.productId,
        imageFileId: image.imageFileId,
        assignedAt: image.assignedAt,
        imageFile: toImageFileRecord(image.imageFile),
      })),
      catalogs: product.catalogs.map((entry) => ({
        productId: entry.productId,
        catalogId: entry.catalogId,
        assignedAt: entry.assignedAt,
        catalog: toCatalogRecord(entry.catalog),
      })),
    }));
  },

  async countProducts(filters: ProductFilters) {
    const where = buildProductWhere(filters);
    return prisma.product.count({ where });
  },

  async getProductById(id: string) {
    const product = await prisma.product.findUnique({
      where: { id },
      include: {
        images: {
          include: { imageFile: true },
          orderBy: { assignedAt: "desc" },
        },
        catalogs: {
          include: {
            catalog: {
              include: {
                languages: {
                  include: { language: true }
                }
              }
            }
          },
        },
      },
    });
    if (!product) return null;
    return {
      ...toProductRecord(product),
      images: product.images.map((image) => ({
        productId: image.productId,
        imageFileId: image.imageFileId,
        assignedAt: image.assignedAt,
        imageFile: toImageFileRecord(image.imageFile),
      })),
      catalogs: product.catalogs.map((entry) => ({
        productId: entry.productId,
        catalogId: entry.catalogId,
        assignedAt: entry.assignedAt,
        catalog: toCatalogRecord(entry.catalog),
      })),
    };
  },

  async getProductBySku(sku: string) {
    const product = await prisma.product.findUnique({ where: { sku } });
    if (!product) return null;
    return toProductRecord(product);
  },

  async findProductByBaseId(baseProductId: string) {
    const product = await prisma.product.findFirst({
      where: { baseProductId },
    });
    if (!product) return null;
    return toProductRecord(product);
  },

  async createProduct(data: CreateProductInput) {
    if (data.sku) {
      const existing = await prisma.product.findUnique({
        where: { sku: data.sku },
        select: { id: true },
      });
      if (existing) {
        throw conflictError("A product with this SKU already exists.", {
          sku: data.sku,
          productId: existing.id,
        });
      }
    }

    const cleanData = removeUndefined(data) as Prisma.ProductCreateInput;
    try {
      const product = await prisma.product.create({ data: cleanData });
      return toProductRecord(product);
    } catch (error) {
      if (
        error instanceof Prisma.PrismaClientKnownRequestError &&
        error.code === "P2002" &&
        Array.isArray(error.meta?.target) &&
        error.meta?.target.includes("sku")
      ) {
        throw conflictError("A product with this SKU already exists.", {
          sku: data.sku ?? null,
        });
      }
      throw error;
    }
  },

  async updateProduct(id: string, data: UpdateProductInput) {
    const productExists = await prisma.product.findUnique({ where: { id } });
    if (!productExists) return null;
    const cleanData = removeUndefined(data) as Prisma.ProductUpdateInput;
    const product = await prisma.product.update({ where: { id }, data: cleanData });
    return toProductRecord(product);
  },

  async deleteProduct(id: string) {
    const productExists = await prisma.product.findUnique({ where: { id } });
    if (!productExists) return null;
    const product = await prisma.product.delete({ where: { id } });
    return toProductRecord(product);
  },

  async duplicateProduct(id: string, sku: string) {
    const product = await prisma.product.findUnique({ where: { id } });
    if (!product) return null;

    const existingSku = await prisma.product.findUnique({
      where: { sku },
      select: { id: true },
    });
    if (existingSku) {
      throw conflictError("A product with this SKU already exists.", {
        sku,
        productId: existingSku.id,
      });
    }

    const duplicated = await prisma.product.create({
      data: {
        name_en: product.name_en,
        name_pl: product.name_pl,
        name_de: product.name_de,
        description_en: product.description_en,
        description_pl: product.description_pl,
        description_de: product.description_de,
        supplierName: product.supplierName,
        supplierLink: product.supplierLink,
        priceComment: product.priceComment,
        stock: product.stock,
        price: product.price,
        sizeLength: product.sizeLength,
        sizeWidth: product.sizeWidth,
        weight: product.weight,
        length: product.length,
        parameters: Array.isArray(product.parameters) ? product.parameters : [],
        imageLinks: Array.isArray(product.imageLinks) ? product.imageLinks : [],
        defaultPriceGroupId: product.defaultPriceGroupId ?? null,
        ean: product.ean ?? null,
        gtin: product.gtin ?? null,
        asin: product.asin ?? null,
        sku,
      },
    });
    return toProductRecord(duplicated);
  },

  async addProductImages(productId: string, imageFileIds: string[]) {
    if (imageFileIds.length === 0) return;
    await prisma.productImage.createMany({
      data: imageFileIds.map((imageFileId) => ({ productId, imageFileId })),
      skipDuplicates: true,
    });
  },

  async replaceProductCatalogs(productId: string, catalogIds: string[]) {
    await prisma.productCatalog.deleteMany({ where: { productId } });
    if (catalogIds.length === 0) return;
    const uniqueIds = Array.from(new Set(catalogIds));
    const existing = await prisma.catalog.findMany({
      where: { id: { in: uniqueIds } },
      select: { id: true },
    });
    const existingIds = new Set(existing.map((entry) => entry.id));
    const validIds = uniqueIds.filter((id) => existingIds.has(id));
    if (validIds.length === 0) return;
    await prisma.productCatalog.createMany({
      data: validIds.map((catalogId) => ({ productId, catalogId })),
    });
  },

  async replaceProductCategories(productId: string, categoryIds: string[]) {
    await prisma.productCategoryAssignment.deleteMany({ where: { productId } });
    if (categoryIds.length === 0) return;
    const uniqueIds = Array.from(new Set(categoryIds));
    const existing = await prisma.productCategory.findMany({
      where: { id: { in: uniqueIds } },
      select: { id: true },
    });
    const existingIds = new Set(existing.map((entry) => entry.id));
    const validIds = uniqueIds.filter((id) => existingIds.has(id));
    if (validIds.length === 0) return;
    await prisma.productCategoryAssignment.createMany({
      data: validIds.map((categoryId) => ({ productId, categoryId })),
    });
  },

  async replaceProductTags(productId: string, tagIds: string[]) {
    await prisma.productTagAssignment.deleteMany({ where: { productId } });
    if (tagIds.length === 0) return;
    const uniqueIds = Array.from(new Set(tagIds));
    const existing = await prisma.productTag.findMany({
      where: { id: { in: uniqueIds } },
      select: { id: true },
    });
    const existingIds = new Set(existing.map((entry) => entry.id));
    const validIds = uniqueIds.filter((id) => existingIds.has(id));
    if (validIds.length === 0) return;
    await prisma.productTagAssignment.createMany({
      data: validIds.map((tagId) => ({ productId, tagId })),
    });
  },

  async removeProductImage(productId: string, imageFileId: string) {
    await prisma.productImage.deleteMany({
      where: { productId, imageFileId },
    });
  },

  async countProductsByImageFileId(imageFileId: string) {
    return prisma.productImage.count({ where: { imageFileId } });
  },
};

import "server-only";

import { ErrorSystem } from "@/features/observability/server";
// This service encapsulates all business logic for managing products.

import fs from "fs/promises";
import path from "path";
import {
  productCreateSchema,
  productUpdateSchema,
} from "@/features/products/validations";
import { getDiskPathFromPublicPath, uploadFile } from "@/features/files/server";
import { getProductRepository } from "@/features/products/services/product-repository";
import type { ProductFilters } from "@/features/products/types/services/product-repository";
import { getImageFileRepository } from "@/features/files/server";
import { getCatalogRepository } from "@/features/products/services/catalog-repository";
import { badRequestError } from "@/shared/errors/app-error";

const resolveProductRepository = async () => getProductRepository();
const resolveImageFileRepository = async () => getImageFileRepository();

/**
 * Retrieves a list of products based on the provided filters.
 * @param filters - The filter criteria.
 * @returns A list of products.
 */
async function getProducts(filters: ProductFilters) {
  const productRepository = await resolveProductRepository();
  const products = await productRepository.getProducts(filters);

  return Promise.all(
    products.map(async (product) => {
      if (!product.images?.length) {
        return product;
      }

      const filteredImages = await Promise.all(
        product.images.map(async (image) => {
          const filepath = image.imageFile?.filepath;
          if (!filepath) {
            return null;
          }

          if (/^(https?:|data:)/i.test(filepath)) {
            return image;
          }

          try {
            await fs.access(getDiskPathFromPublicPath(filepath));
            return image;
          } catch {
            return null;
          }
        })
      );

      return {
        ...product,
        images: filteredImages.filter(Boolean),
      };
    })
  );
}

/**
 * Counts the total number of products based on filters.
 * @param filters - The filter criteria.
 * @returns The total count.
 */
async function countProducts(filters: ProductFilters) {
  const productRepository = await resolveProductRepository();
  return productRepository.countProducts(filters);
}

/**
 * Retrieves a single product by its ID.
 * @param id - The ID of the product to retrieve.
 * @returns The product, or null if not found.
 */
async function getProductById(id: string) {
  const productRepository = await resolveProductRepository();
  return productRepository.getProductById(id);
}

async function getProductBySku(sku: string) {
  const productRepository = await resolveProductRepository();
  const product = await productRepository.getProductBySku(sku);
  if (!product) return null;
  return getProductById(product.id);
}

/**
 * Creates a new product.
 * @param formData - The product data from the form.
 * @returns The newly created product.
 */
async function createProduct(formData: FormData) {
  await ErrorSystem.logInfo("Creating product...");
  try {
    const validatedData = productCreateSchema.parse(
      Object.fromEntries(formData.entries())
    );
    await ErrorSystem.logInfo("Validated data", { validatedData });
    const productRepository = await resolveProductRepository();
    const product = await productRepository.createProduct(validatedData);

    const images = formData.getAll("images") as File[];
    const imageFileIds = formData.getAll("imageFileIds") as string[];
    const catalogIds = normalizeCatalogIds(formData.getAll("catalogIds"));
    const categoryIds = normalizeCategoryIds(formData.getAll("categoryIds"));
    const tagIds = normalizeTagIds(formData.getAll("tagIds"));
    await linkImagesToProduct(
      product.id,
      images,
      imageFileIds,
      validatedData.sku
    );
    await updateProductCatalogs(product.id, catalogIds);
    await updateProductCategories(product.id, categoryIds);
    await updateProductTags(product.id, tagIds);

    return await getProductById(product.id);
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "productService",
      action: "createProduct",
    });
    throw error;
  }
}

/**
 * Updates an existing product.
 * @param id - The ID of the product to update.
 * @param formData - The updated product data from the form.
 * @returns The updated product, or null if not found.
 */
async function updateProduct(id: string, formData: FormData) {
  await ErrorSystem.logInfo(`Updating product ${id}...`);
  try {
    const validatedData = productUpdateSchema.parse(
      Object.fromEntries(formData.entries())
    );
    await ErrorSystem.logInfo("Validated data", { validatedData });
    const productRepository = await resolveProductRepository();
    const updatedProduct = await productRepository.updateProduct(
      id,
      validatedData
    );
    if (!updatedProduct) return null;

    const images = formData.getAll("images") as File[];
    const imageFileIds = formData.getAll("imageFileIds") as string[];
    await linkImagesToProduct(id, images, imageFileIds, validatedData.sku);
    if (validatedData.sku) {
      await moveLinkedTempImagesToSku(id, validatedData.sku);
    }

    // Only update catalogs/categories/tags if explicitly provided in formData
    if (formData.has("catalogIds")) {
      const catalogIds = normalizeCatalogIds(formData.getAll("catalogIds"));
      await updateProductCatalogs(id, catalogIds);
    }
    if (formData.has("categoryIds")) {
      const categoryIds = normalizeCategoryIds(formData.getAll("categoryIds"));
      await updateProductCategories(id, categoryIds);
    }
    if (formData.has("tagIds")) {
      const tagIds = normalizeTagIds(formData.getAll("tagIds"));
      await updateProductTags(id, tagIds);
    }

    return await getProductById(updatedProduct.id);
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "productService",
      action: "updateProduct",
      productId: id,
    });
    throw error;
  }
}

/**
 * Deletes a product.
 * @param id - The ID of the product to delete.
 * @returns The deleted product, or null if not found.
 */
async function deleteProduct(id: string) {
  await ErrorSystem.logInfo(`Deleting product ${id}...`);
  try {
    const productRepository = await resolveProductRepository();
    return await productRepository.deleteProduct(id);
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "productService",
      action: "deleteProduct",
      productId: id,
    });
    throw error;
  }
}

/**
 * Duplicates a product without images and with a new SKU.
 * @param id - The ID of the product to duplicate.
 * @param sku - The new SKU for the duplicated product.
 * @returns The duplicated product, or null if not found.
 */
async function duplicateProduct(id: string, sku: string) {
  await ErrorSystem.logInfo(`Duplicating product ${id} with new SKU ${sku}...`);
  try {
    const trimmedSku = sku.trim();
    const skuPattern = /^[A-Z0-9]+$/;
    if (!trimmedSku) {
      throw badRequestError("SKU is required", { field: "sku" });
    }
    if (!skuPattern.test(trimmedSku)) {
      throw badRequestError("SKU must use uppercase letters and numbers only", {
        field: "sku",
        value: trimmedSku,
      });
    }

    const productRepository = await resolveProductRepository();
    const duplicatedProduct = await productRepository.duplicateProduct(
      id,
      trimmedSku
    );
    if (!duplicatedProduct) return null;
    return await getProductById(duplicatedProduct.id);
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "productService",
      action: "duplicateProduct",
      productId: id,
      newSku: sku,
    });
    throw error;
  }
}

/**
 * Unlinks an image from a product.
 * @param productId - The ID of the product.
 * @param imageFileId - The ID of the image file.
 * @returns The result of the deletion.
 */
// Why: Images may be linked to multiple products. Only delete the physical file
// and folder after confirming no other products reference this image. This prevents
// accidental data loss if the same image is reused and orphaned disk directories
// from cluttering the storage.
async function unlinkImageFromProduct(productId: string, imageFileId: string) {
  const productRepository = await resolveProductRepository();
  const imageFileRepository = await resolveImageFileRepository();
  await productRepository.removeProductImage(productId, imageFileId);
  const remainingLinks =
    await productRepository.countProductsByImageFileId(imageFileId);

  if (remainingLinks === 0) {
    const imageFile = await imageFileRepository.getImageFileById(imageFileId);

    if (imageFile) {
      const isExternal = /^https?:\/\//i.test(imageFile.filepath);
      if (!isExternal) {
        try {
          await fs.unlink(getDiskPathFromPublicPath(imageFile.filepath));
        } catch (error: unknown) {
          if (error instanceof Error && (error as NodeJS.ErrnoException).code !== "ENOENT") {
            throw error;
          }
        }
      }

      await imageFileRepository.deleteImageFile(imageFileId);

      if (!isExternal) {
        const folderDiskPath = path.dirname(
          getDiskPathFromPublicPath(imageFile.filepath)
        );
        if (folderDiskPath.startsWith(path.join(process.cwd(), "public", "uploads", "products"))) {
          try {
            const folderContents = await fs.readdir(folderDiskPath);
            if (folderContents.length === 0) {
              await fs.rmdir(folderDiskPath);
            }
          } catch (error: unknown) {
            if (error instanceof Error && (error as NodeJS.ErrnoException).code !== "ENOENT") {
              throw error;
            }
          }
        }
      }
    }
  }

  return null;
}

/**
 * Links images to a product. This includes uploading new images and linking existing ones.
 * @param productId - The ID of the product.
 * @param images - The new image files to upload.
 * @param imageFileIds - The IDs of the existing image files to link.
 */
async function linkImagesToProduct(
  productId: string,
  images: File[],
  imageFileIds: string[],
  productSku?: string | null
) {
  const productRepository = await resolveProductRepository();
  const allImageFileIds = [...imageFileIds];

  if (images.length > 0) {
    for (const image of images) {
      // Filter out empty file inputs
      if (image.size > 0) {
        const uploadedImage = await uploadFile(image, {
          category: "products",
          sku: productSku,
        });
        allImageFileIds.push(uploadedImage.id);
      }
    }
  }

  if (productSku && imageFileIds.length > 0) {
    await moveTempImageFilesToSku(imageFileIds, productSku);
  }

  if (allImageFileIds.length > 0) {
    await productRepository.addProductImages(productId, allImageFileIds);
  }
}

const tempProductPathPrefix = "/uploads/products/temp/";

// Why: HTML form's getAll("catalogIds") returns entries for EACH selected item.
// Normalize to trim whitespace (user selection artifacts) and filter empty strings
// (unchecked checkboxes). This prevents invalid IDs from entering the database.
function normalizeCatalogIds(entries: FormDataEntryValue[]) {
  return entries
    .map((entry) => (typeof entry === "string" ? entry.trim() : ""))
    .filter((entry) => entry.length > 0);
}

function normalizeCategoryIds(entries: FormDataEntryValue[]) {
  return entries
    .map((entry) => (typeof entry === "string" ? entry.trim() : ""))
    .filter((entry) => entry.length > 0);
}

function normalizeTagIds(entries: FormDataEntryValue[]) {
  return entries
    .map((entry) => (typeof entry === "string" ? entry.trim() : ""))
    .filter((entry) => entry.length > 0);
}

async function updateProductCatalogs(productId: string, catalogIds: string[]) {
  const productRepository = await resolveProductRepository();
  await productRepository.replaceProductCatalogs(productId, catalogIds);

  // Why: Products need a default price group for inventory/listing calculations.
  // Auto-assigning from the first assigned catalog prevents incomplete product state.
  // Only sets it if the product doesn't already have one to preserve manual overrides.
  const firstCatalogId = catalogIds[0];
  if (firstCatalogId) {
    const product = await productRepository.getProductById(productId);
    if (product && !product.defaultPriceGroupId) {
      const catalogRepository = await getCatalogRepository();
      const catalog = await catalogRepository.getCatalogById(firstCatalogId);
      if (catalog?.defaultPriceGroupId) {
        await productRepository.updateProduct(productId, {
          defaultPriceGroupId: catalog.defaultPriceGroupId,
        });
      }
    }
  }
}

async function updateProductCategories(productId: string, categoryIds: string[]) {
  const productRepository = await resolveProductRepository();
  await productRepository.replaceProductCategories(productId, categoryIds);
}

async function updateProductTags(productId: string, tagIds: string[]) {
  const productRepository = await resolveProductRepository();
  await productRepository.replaceProductTags(productId, tagIds);
}

// Why: Temp path allows users to upload images before saving a product. Once a
// SKU is assigned, we permanently organize images by SKU for easy product recovery.
// Sanitization (replacing non-alphanumeric with underscore) prevents path injection
// and filesystem-specific naming issues across different OS environments.
async function moveTempImageFilesToSku(imageFileIds: string[], sku: string) {
  const imageFileRepository = await resolveImageFileRepository();
  const imageFiles = await imageFileRepository.findImageFilesByIds(
    imageFileIds
  );

  for (const imageFile of imageFiles) {
    if (!imageFile.filepath.startsWith(tempProductPathPrefix)) {
      continue;
    }

    const filename = imageFile.filepath.slice(tempProductPathPrefix.length);
    const safeSku = sku.trim().replace(/[^a-zA-Z0-9-_]/g, "_");
    const targetPublicDir = `/uploads/products/${safeSku}`;
    const targetPublicPath = `${targetPublicDir}/${filename}`;

    await fs.mkdir(
      path.join(process.cwd(), "public", "uploads", "products", safeSku),
      { recursive: true }
    );
    await fs.rename(
      getDiskPathFromPublicPath(imageFile.filepath),
      getDiskPathFromPublicPath(targetPublicPath)
    );

    await imageFileRepository.updateImageFilePath(
      imageFile.id,
      targetPublicPath
    );
  }
}

async function moveLinkedTempImagesToSku(productId: string, sku: string) {
  const productRepository = await resolveProductRepository();
  const product = await productRepository.getProductById(productId);
  const imageFileIds =
    product?.images
      .filter((image) =>
        image.imageFile.filepath.startsWith(tempProductPathPrefix)
      )
      .map((image) => image.imageFileId) ?? [];
  if (imageFileIds.length > 0) {
    await moveTempImageFilesToSku(imageFileIds, sku);
  }
}

